Question: How many consecutive days did the average sleep_average_oxygen_saturation in oxygen_sat_daily across all users increase, starting from 2022-06-17?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg AS (
    SELECT DATE(ts) AS date, AVG(sleep_average_oxygen_saturation) AS avg_oxygen_saturation
    FROM oxygen_sat_daily
    WHERE DATE(ts) >= '2022-06-17'
    GROUP BY DATE(ts)
),
consecutive_days AS (
    SELECT date, avg_oxygen_saturation,
           @prev_avg := @curr_avg AS prev_avg,
           @curr_avg := avg_oxygen_saturation,
           @is_increasing := IF(@curr_avg > @prev_avg, @is_increasing + 1, 1) AS streak
    FROM daily_avg, (SELECT @curr_avg := NULL, @prev_avg := NULL, @is_increasing := 0) AS vars
    ORDER BY date
)
SELECT MAX(streak) AS consecutive_increase_days
FROM consecutive_days;

