Question: How many consecutive days did the average nightly_temperature in skin_temp_sleep_nightly across all users increase, starting from 2022-06-07?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg_temp AS (
    SELECT DATE(start_sleep) AS sleep_date, AVG(nightly_temperature) AS avg_temp
    FROM skin_temp_sleep_nightly
    WHERE DATE(start_sleep) >= '2022-06-07'
    GROUP BY sleep_date
),
temp_increase AS (
    SELECT sleep_date, avg_temp,
           @prev_temp := IF(@prev_temp IS NULL, avg_temp, @prev_temp) AS prev_temp,
           @is_increasing := IF(avg_temp > @prev_temp, @is_increasing + 1, 1) AS streak
    FROM daily_avg_temp, (SELECT @prev_temp := NULL, @is_increasing := 0) AS vars
    ORDER BY sleep_date
)
SELECT MAX(streak) AS consecutive_days_increase
FROM temp_increase;

