Question: How many consecutive days did A4F_73455's frequency of meals cooked with cooking_style 'Fresh' in food_meal_labels increase, while his/her minutes_in_rem in additional_sleep also increased, starting from 2022-05-26?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH meal_counts AS (
    SELECT DATE(ts) AS meal_date, COUNT(*) AS meal_count
    FROM food_meal_labels
    WHERE id = 'A4F_73455' AND cooking_style = 'Fresh' AND DATE(ts) >= '2022-05-26'
    GROUP BY meal_date
),
sleep_data AS (
    SELECT DATE(start_time) AS sleep_date, SUM(minutes_in_rem) AS total_rem
    FROM additional_sleep
    WHERE id = 'A4F_73455' AND DATE(start_time) >= '2022-05-26'
    GROUP BY sleep_date
),
combined AS (
    SELECT m.meal_date, m.meal_count, s.total_rem
    FROM meal_counts m
    JOIN sleep_data s ON m.meal_date = s.sleep_date
    ORDER BY m.meal_date
),
consecutive_days AS (
    SELECT meal_date, meal_count, total_rem,
           @prev_meal_count := IF(@prev_meal_count IS NULL, meal_count, @prev_meal_count) AS prev_meal_count,
           @prev_rem := IF(@prev_rem IS NULL, total_rem, @prev_rem) AS prev_rem,
           @is_consecutive := IF(meal_count > @prev_meal_count AND total_rem > @prev_rem, @is_consecutive + 1, 1) AS consecutive_count,
           @prev_meal_count := meal_count,
           @prev_rem := total_rem
    FROM combined, (SELECT @prev_meal_count := NULL, @prev_rem := NULL, @is_consecutive := 0) AS vars
)
SELECT MAX(consecutive_count) AS consecutive_days
FROM consecutive_days;

