Question: How many consecutive days did A4F_93308's {calories} in pa_reports burned in Walk increase, starting from 2022-05-24?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_calories AS (
    SELECT DATE(record_ts) AS report_date, calories
    FROM pa_reports
    WHERE id = 'A4F_93308' AND activity_name = 'Walk' AND DATE(record_ts) >= '2022-05-24'
)
SELECT COUNT(*) AS consecutive_days
FROM (
    SELECT report_date, calories,
           @prev_calories := IF(@prev_calories IS NULL, calories, @prev_calories) AS prev_calories,
           @prev_calories := calories,
           @is_increasing := IF(calories > @prev_calories, 1, 0) AS is_increasing,
           @prev_date := IF(@prev_date IS NULL, report_date, @prev_date) AS prev_date,
           @prev_date := report_date
    FROM daily_calories, (SELECT @prev_calories := NULL, @prev_date := NULL, @is_increasing := 0) AS vars
    ORDER BY report_date
) AS subquery
WHERE is_increasing = 1;

